                <div><h3 style={{ margin: "0 0 8px", fontSize: 17, color: "#e2e8f0" }}>{step.title}</h3><p style={{ ...pStyle, fontSize: 14, marginBottom: 0 }}>{step.body}</p>{step.code && <code style={codeStyle}>{step.code}</code>}</div>
